    MOCK_MEDICATIONS.filter(m => m.name.toLowerCase().includes(query.toLowerCase()) || m.category.toLowerCase().includes(query.toLowerCase())),
    [query]
  );

  const filteredPharmacies = useMemo(() => 
    MOCK_PHARMACIES.filter(p => p.name.toLowerCase().includes(query.toLowerCase()) || p.address.toLowerCase().includes(query.toLowerCase())),
    [query]
  );

  return (
