                    </button>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="text-center py-20 bg-white rounded-[2rem] border border-dashed border-slate-200 text-slate-400 font-bold">Nenhum medicamento encontrado em Maputo.</div>
          )
        ) : (
          filteredPharmacies.length > 0 ? (
            filteredPharmacies.map((pharm) => (
